 1	import { Dropdown, DropdownItem, MenuToggle, MenuToggleElement } from '@patternfly/react-core';
 2	import * as _ from 'lodash';
 3	import * as React from 'react';
 4	import { useTranslation } from 'react-i18next';
 5	import { formatDuration, parseDuration } from '../../utils/duration';
 6	
 7	export interface RefreshDropdownProps {
 8	  disabled?: boolean;
 9	  interval?: number;
10	  setInterval: (v?: number) => void;
11	  id?: string;
12	}
13	
14	const offKey = 'OFF_KEY';
15	
16	export const RefreshDropdown: React.FC<RefreshDropdownProps> = ({ disabled, id, interval, setInterval }) => {
17	  const [isOpen, setOpen] = React.useState<boolean>(false);
18	  const { t } = useTranslation('plugin__netobserv-plugin');
19	
20	  const onChange = React.useCallback(
21	    (v: string) => setInterval(v === offKey ? undefined : parseDuration(v)),
22	    [setInterval]
23	  );
24	
25	  const refreshOptions = {
26	    OFF_KEY: t('Refresh off'),
27	    '15s': t('15 seconds'),
28	    '30s': t('30 seconds'),
29	    '1m': t('1 minute'),
30	    '5m': t('5 minutes'),
31	    '15m': t('15 minutes'),
32	    '30m': t('30 minutes'),
33	    '1h': t('1 hour'),
34	    '2h': t('2 hours'),
35	    '1d': t('1 day')
36	  };
37	
38	  const selectedKey = interval === undefined ? offKey : formatDuration(interval);
39	
40	  //unselect interval when dropdown is disabled
41	  React.useEffect(() => {
42	    if (disabled && interval) {
43	      setInterval(undefined);
44	    }
45	  }, [disabled, interval, setInterval]);
46	
47	  return (
48	    <div id={`${id}-container`}>
49	      <Dropdown
50	        data-test={id}
51	        id={id}
52	        isOpen={isOpen}
53	        onSelect={() => setOpen(false)}
54	        toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
55	          <MenuToggle
56	            ref={toggleRef}
57	            data-test={`${id}-dropdown`}
58	            id={`${id}-dropdown`}
59	            isDisabled={disabled}
60	            onClick={() => setOpen(!isOpen)}
61	            onBlur={() => setTimeout(() => setOpen(false), 500)}
62	            isExpanded={isOpen}
63	          >
64	            {refreshOptions[selectedKey as keyof typeof refreshOptions]}
65	          </MenuToggle>
66	        )}
67	      >
68	        {_.map(refreshOptions, (name, key) => (
69	          <DropdownItem data-test={key} id={key} component="button" key={key} onClick={() => onChange(key)}>
70	            {name}
71	          </DropdownItem>
72	        ))}
73	      </Dropdown>
74	    </div>
75	  );
76	};
77	
78	export default RefreshDropdown;

