 1	import { act, fireEvent, render, screen, waitFor } from '@testing-library/react';
 2	import userEvent from '@testing-library/user-event';
 3	import * as React from 'react';
 4	
 5	import { RefreshDropdown, RefreshDropdownProps } from '../refresh-dropdown';
 6	
 7	describe('<RefreshDropdown />', () => {
 8	  const props: RefreshDropdownProps = {
 9	    interval: undefined,
10	    setInterval: jest.fn(),
11	    id: 'refresh'
12	  };
13	
14	  it('should render component', async () => {
15	    render(<RefreshDropdown {...props} />);
16	    expect(screen.getByRole('button')).toHaveAttribute('id', 'refresh-dropdown');
17	  });
18	
19	  it('should open and close', async () => {
20	    const { container } = render(<RefreshDropdown {...props} />);
21	
22	    await act(async () => {
23	      fireEvent.click(container.querySelector('#refresh-dropdown')!);
24	    });
25	    await waitFor(() => {
26	      expect(document.querySelectorAll('[role="menu"] li').length).toBeGreaterThan(0);
27	    });
28	
29	    await act(async () => {
30	      fireEvent.click(container.querySelector('#refresh-dropdown')!);
31	    });
32	
33	    expect(props.setInterval).toHaveBeenCalledTimes(0);
34	  });
35	
36	  it('should refresh on select', async () => {
37	    const user = userEvent.setup();
38	    const { container } = render(<RefreshDropdown {...props} />);
39	
40	    await act(async () => {
41	      fireEvent.click(container.querySelector('#refresh-dropdown')!);
42	    });
43	    await waitFor(() => expect(document.querySelector('#OFF_KEY')).toBeTruthy());
44	
45	    await user.click(document.querySelector('#OFF_KEY')!);
46	    expect(props.setInterval).toHaveBeenCalledWith(undefined);
47	
48	    await act(async () => {
49	      fireEvent.click(container.querySelector('#refresh-dropdown')!);
50	    });
51	    await waitFor(() => expect(document.querySelector('[id="15s"]')).toBeTruthy());
52	
53	    await user.click(document.querySelector('[id="15s"]')!);
54	
55	    expect(props.setInterval).toHaveBeenCalledTimes(2);
56	    expect(props.setInterval).toHaveBeenCalledWith(15000);
57	  });
58	});

